import{_ as a,o as t,c as i,ag as o}from"./chunks/framework.BPmc_f4o.js";const u=JSON.parse('{"title":"IP Filtering","description":"","frontmatter":{},"headers":[],"relativePath":"ipsfilter/ipsfilter.md","filePath":"ipsfilter/ipsfilter.md"}'),r={name:"ipsfilter/ipsfilter.md"};function n(l,e,s,d,c,p){return t(),i("div",null,[...e[0]||(e[0]=[o('<p><span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#2e7d32;color:#fff;font-size:11px;font-weight:600;">FREE</span> <span style="display:inline-block;padding:1px 8px;border-radius:3px;background:#1565c0;color:#fff;font-size:11px;font-weight:600;">PRO</span></p><h1 id="ip-filtering" tabindex="-1">IP Filtering <a class="header-anchor" href="#ip-filtering" aria-label="Permalink to &quot;IP Filtering&quot;">​</a></h1><p>IP Filtering controls which IP addresses can reach the REST API. The free tier provides automatic and manual IP blacklisting. Pro adds whitelist mode, CIDR range support, and country-level blocking — all scoped per application.</p><hr><h2 id="free-tier" tabindex="-1">Free Tier <a class="header-anchor" href="#free-tier" aria-label="Permalink to &quot;Free Tier&quot;">​</a></h2><h3 id="automatic-blacklisting" tabindex="-1">Automatic Blacklisting <a class="header-anchor" href="#automatic-blacklisting" aria-label="Permalink to &quot;Automatic Blacklisting&quot;">​</a></h3><p>The plugin monitors rate limit violations. When an IP exceeds the blacklist threshold configured in the <a href="/users/users.html">Auth &amp; Rate Limiting</a> panel, it is added to the blacklist automatically. The Block Time setting determines how long the IP remains blocked.</p><h3 id="manual-blacklist" tabindex="-1">Manual Blacklist <a class="header-anchor" href="#manual-blacklist" aria-label="Permalink to &quot;Manual Blacklist&quot;">​</a></h3><p>IPs can be added to the blacklist manually at any time. Entries can also be removed individually.</p><p>Free tier supports <strong>IPv4 addresses</strong> only. CIDR ranges and IPv6 are not available.</p><h3 id="geoip-statistics" tabindex="-1">GeoIP Statistics <a class="header-anchor" href="#geoip-statistics" aria-label="Permalink to &quot;GeoIP Statistics&quot;">​</a></h3><p>Read-only geographic statistics of incoming requests are available in the free tier. Country-level blocking is not available — it requires Pro.</p><hr><h2 id="pro-—-modes" tabindex="-1">Pro — Modes <a class="header-anchor" href="#pro-—-modes" aria-label="Permalink to &quot;Pro — Modes&quot;">​</a></h2><p>In Pro, IP Filtering is scoped per application. Each application can operate in a different mode.</p><h3 id="blacklist-mode" tabindex="-1">Blacklist Mode <a class="header-anchor" href="#blacklist-mode" aria-label="Permalink to &quot;Blacklist Mode&quot;">​</a></h3><p>Listed IPs and ranges are blocked. A configurable <strong>retention time</strong> determines how long a blacklisted entry remains active before it is automatically removed.</p><h3 id="whitelist-mode" tabindex="-1">Whitelist Mode <a class="header-anchor" href="#whitelist-mode" aria-label="Permalink to &quot;Whitelist Mode&quot;">​</a></h3><p>Only IPs explicitly listed are allowed through. All other IPs are rejected. Use this mode when your application is accessed from known, fixed IP addresses (e.g. a CI server or an internal corporate network).</p><hr><h2 id="pro-—-advanced-options" tabindex="-1">Pro — Advanced Options <a class="header-anchor" href="#pro-—-advanced-options" aria-label="Permalink to &quot;Pro — Advanced Options&quot;">​</a></h2><h3 id="cidr-ranges" tabindex="-1">CIDR Ranges <a class="header-anchor" href="#cidr-ranges" aria-label="Permalink to &quot;CIDR Ranges&quot;">​</a></h3><p>Define IP ranges using CIDR notation (e.g. <code>192.168.1.0/24</code>). Works in both whitelist and blacklist modes.</p><h3 id="country-blocking" tabindex="-1">Country Blocking <a class="header-anchor" href="#country-blocking" aria-label="Permalink to &quot;Country Blocking&quot;">​</a></h3><p>Block or allow requests by country using GeoIP data. Two sub-modes available:</p><ul><li><strong>Block countries</strong> — allow all traffic except the listed countries.</li><li><strong>Allow countries</strong> — block all traffic except the listed countries.</li></ul><p>Country rules apply on top of individual IP rules.</p><hr><h2 id="ip-list-management" tabindex="-1">IP List Management <a class="header-anchor" href="#ip-list-management" aria-label="Permalink to &quot;IP List Management&quot;">​</a></h2><p>The IP list displays all active entries (manual or auto-detected). For each entry:</p><ul><li><strong>Add</strong> an IP or CIDR range manually.</li><li><strong>Delete</strong> one or more entries.</li></ul><p>Entries show the IP address, source (manual or auto-detected), and — in Pro — the retention expiry time.</p><hr><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><p><strong>Is IP filtering per application in Pro?</strong></p><p>Yes. Each application has its own IP list and operates in its own mode (whitelist or blacklist). An IP blocked in one application is not affected in another.</p><p><strong>Does the auto-blacklist work in Pro?</strong></p><p>Yes. Rate limit auto-detection works in both tiers. In Pro, the resulting blacklist entry is scoped to the application that detected the violation.</p><p><strong>Are IPv6 addresses supported?</strong></p><p>IPv6 support is available in Pro with CIDR notation. The free tier supports IPv4 only.</p><p><strong>What happens to blocked IPs when an application is deleted?</strong></p><p>IP entries scoped to a deleted application are removed alongside it. Global free-tier entries are unaffected.</p>',42)])])}const g=a(r,[["render",n]]);export{u as __pageData,g as default};
